// ─────────────────────────────────────────────
// VHSYS :: update_services
// Rota   : PUT /update_services
// Fase 2 : Núcleo de status e controle
// ─────────────────────────────────────────────
// Input  : { ACTION: string, RUNNING_STATUS: int }
// Output : { message: 'Update extension service status' } HTTP 201
// Banco  : UPDATE update_extension_services SET RUN_STATUS, LAST_UPDATE
// Chave  : ACTION (PK)
// ─────────────────────────────────────────────

const body = $input.first().json.body || {};
const ACTION = (body.ACTION || '').toString().trim();
const RUNNING_STATUS = parseInt(body.RUNNING_STATUS, 10);

const errors = [];

if (!ACTION) {
  errors.push('Campo ACTION é obrigatório');
}
if (isNaN(RUNNING_STATUS)) {
  errors.push('Campo RUNNING_STATUS deve ser número inteiro');
} else if (![0, 1, 2, -1].includes(RUNNING_STATUS)) {
  errors.push('RUNNING_STATUS inválido. Valores aceitos: -1 (erro), 0 (parado), 1 (em execução), 2 (finalizado)');
}

if (errors.length > 0) {
  console.log(JSON.stringify({
    timestamp: new Date().toISOString(),
    route: 'update_services',
    event: 'validation_failed',
    errors,
    level: 'warn'
  }));
  return {
    _valid: false,
    _errors: errors,
    statusCode: 400,
    body: { ok: false, error: 'Validation failed', details: errors }
  };
}

console.log(JSON.stringify({
  timestamp: new Date().toISOString(),
  route: 'update_services',
  event: 'input_validated',
  action: ACTION,
  run_status: RUNNING_STATUS,
  level: 'info'
}));

return {
  _valid: true,
  ACTION,
  RUNNING_STATUS
};

// ── Sucesso: ACTION foi atualizado no banco ──
const dbRow = $input.first().json;

console.log(JSON.stringify({
  timestamp: new Date().toISOString(),
  route: 'update_services',
  event: 'status_updated',
  action: dbRow.ACTION,
  run_status: dbRow.RUN_STATUS,
  last_update: dbRow.LAST_UPDATE,
  level: 'info'
}));

return {
  statusCode: 201,
  body: { message: 'Update extension service status' }
};

// ── Erro do Postgres (ACTION não existe ou falha de conexão) ──
const errData = $input.first().json;

console.log(JSON.stringify({
  timestamp: new Date().toISOString(),
  route: 'update_services',
  event: 'db_error',
  message: errData.message || 'Unknown DB error',
  level: 'error'
}));

return {
  statusCode: 500,
  body: { ok: false, error: 'Database error', message: 'Could not update service status' }
};

// ── Erro de validação (input inválido) ──
const input = $input.first().json;

return {
  statusCode: input.statusCode || 400,
  body: input.body || { ok: false, error: 'Validation failed' }
};
